option.value:
.home-page {
  margin-top: 60px;
  padding: 34px 20px 56px;
  background:
    radial-gradient(circle at 4% 8%, rgba(34, 197, 94, 0.14), transparent 32%),
    radial-gradient(circle at 96% 92%, rgba(34, 197, 94, 0.1), transparent 36%),
    linear-gradient(180deg, #f0fdf4 0%, #f7fef5 100%);
  min-height: calc(100vh - 60px);
}

.home-hero {
  max-width: 1100px;
  margin: 0 auto 28px;
  background:
    linear-gradient(135deg, rgba(255, 255, 255, 0.96) 0%, rgba(240, 253, 244, 0.94) 100%);
  border: 1px solid rgba(21, 128, 61, 0.18);
  border-radius: 20px;
  box-shadow: 0 18px 42px rgba(21, 128, 61, 0.12);
  padding: 32px 26px;
  position: relative;
  overflow: hidden;
}

.home-hero::before {
  content: "";
  position: absolute;
  top: -60px;
  right: -80px;
  width: 210px;
  height: 210px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(34, 197, 94, 0.18) 0%, rgba(34, 197, 94, 0) 70%);
}

.home-hero h1 {
  margin: 8px 0 10px;
  font-size: clamp(1.45rem, 2.8vw, 2.28rem);
  color: #14532d;
}

.home-subtitle {
  color: #2f5f4b;
  line-height: 1.65;
  max-width: 760px;
}

.home-hero-actions {
  margin-top: 18px;
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
}

.home-btn-primary,
.home-btn-secondary {
  display: inline-block;
  border-radius: 12px;
  padding: 11px 18px;
  font-weight: 700;
  text-decoration: none;
  transition: transform 0.16s ease, box-shadow 0.16s ease, background-color 0.16s ease;
}

.home-btn-primary {
  color: #ffffff;
  background: linear-gradient(135deg, #15803d 0%, #22c55e 100%);
  box-shadow: 0 10px 22px rgba(34, 197, 94, 0.28);
}

.home-btn-secondary {
  color: #15803d;
  background: #ecfdf3;
  border: 1px solid #bbf7d0;
}

.home-btn-primary:hover,
.home-btn-secondary:hover {
  transform: translateY(-1px);
}

.home-section-shell {
  max-width: 1100px;
  margin: 0 auto;
  display: grid;
  gap: 18px;
}

.home-stocks-section {
  background: #ffffff;
  border: 1px solid rgba(21, 128, 61, 0.14);
  border-radius: 20px;
  box-shadow: 0 16px 36px rgba(21, 128, 61, 0.09);
  padding: 24px;
}

.stocks-top-row {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 10px;
  flex-wrap: wrap;
}

.stocks-top-row h2 {
  margin: 0;
}

.stocks-top-row p {
  margin: 0;
  color: #38644f;
  font-size: 0.92rem;
}

.stocks-feed-row {
  margin-top: 10px;
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}

.feed-pill {
  border-radius: 999px;
  padding: 5px 10px;
  font-size: 0.76rem;
  font-weight: 700;
  letter-spacing: 0.02em;
}

.feed-pill.idle {
  color: #455a64;
  background: #eceff1;
}

.feed-pill.connecting {
  color: #7a5600;
  background: #fff7de;
}

.feed-pill.live {
  color: #0c7a40;
  background: #e9f8ef;
}

.feed-pill.error {
  color: #b02a2a;
  background: #ffecec;
}

.feed-error-inline {
  color: #b02a2a;
  font-size: 0.82rem;
}

.search-wrapper {
  margin-top: 12px;
}

.search-label {
  display: block;
  margin-bottom: 8px;
  font-size: 0.9rem;
  font-weight: 600;
  color: #1f5139;
}

.stock-search-input {
  width: 100%;
  box-sizing: border-box;
  border: 1px solid #bbe5ca;
  border-radius: 10px;
  background: #f8fff9;
  padding: 12px 14px;
  font-size: 0.95rem;
}

.stock-search-input:focus {
  outline: none;
  border-color: #15803d;
  box-shadow: 0 0 0 3px rgba(21, 128, 61, 0.15);
}

.stocks-grid {
  margin-top: 16px;
  display: grid;
  gap: 14px;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
}

.stock-card {
  border: 1px solid #d2f0dd;
  border-radius: 16px;
  background: linear-gradient(180deg, #ffffff 0%, #f8fff9 100%);
  padding: 13px;
  display: flex;
  flex-direction: column;
  min-height: 0;
  transition: transform 0.16s ease, box-shadow 0.16s ease, border-color 0.16s ease;
}

.stock-card:hover {
  transform: translateY(-2px);
  border-color: #a9e4bf;
  box-shadow: 0 12px 24px rgba(21, 128, 61, 0.14);
}

.stock-card-header {
  display: flex;
  justify-content: space-between;
  gap: 8px;
}

.stock-card-header > div {
  min-width: 0;
}

.stock-card-header h3 {
  margin: 0;
  color: #14532d;
}

.stock-card-header p {
  margin: 4px 0 0;
  color: #4a6b5b;
  font-size: 0.88rem;
  overflow-wrap: anywhere;
}

.recommendation-badge {
  align-self: flex-start;
  flex-shrink: 0;
  border-radius: 999px;
  font-size: 0.72rem;
  font-weight: 700;
  padding: 4px 9px;
  white-space: nowrap;
}

.recommendation-badge.buy {
  color: #0c7a40;
  background: #e9f8ef;
}

.recommendation-badge.hold {
  color: #8f6400;
  background: #fff7de;
}

.recommendation-badge.sell {
  color: #b02a2a;
  background: #ffecec;
}

.recommendation-badge.active {
  color: #0c7a40;
  background: #e9f8ef;
}

.recommendation-badge.inactive {
  color: #666666;
  background: #f0f0f0;
}

/* ── Market session badges ── */
.recommendation-badge.session-regular {
  color: #0c7a40;
  background: #e9f8ef;
  border: 1px solid #a8e6c0;
}

.recommendation-badge.session-pre-market {
  color: #6b4f00;
  background: #fff3cd;
  border: 1px solid #f5cc60;
}

.recommendation-badge.session-after-hours {
  color: #6a1b9a;
  background: #f3e5f5;
  border: 1px solid #ce93d8;
}

.recommendation-badge.session-closed {
  color: #5a5a5a;
  background: #f0f0f0;
  border: 1px solid #d0d0d0;
}

.quote-price-row {
  margin-top: 10px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.quote-price-row strong {
  font-size: 1.4rem;
  color: #14532d;
}

.price-up {
  color: #138a4f;
  font-weight: 700;
}

.price-down {
  color: #c0392b;
  font-weight: 700;
}

.quote-block,
.trade-block,
.aggregate-block {
  margin-top: 10px;
  border: 1px solid #d2f0dd;
  border-radius: 12px;
  padding: 8px;
  background: #f9fffb;
}

.trade-block {
  background: #fcfefc;
}

.aggregate-block {
  background: #f9fffb;
}

.block-title {
  margin: 0 0 6px;
  font-size: 0.72rem;
  font-weight: 700;
  color: #3b7058;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.quote-grid,
.trade-grid,
.aggregate-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px 10px;
}

.quote-grid p,
.trade-grid p,
.aggregate-grid p {
  margin: 0;
  font-size: 0.82rem;
  color: #315b49;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 6px;
  min-height: 24px;
  min-width: 0;
}

.metric-item-full {
  grid-column: 1 / -1;
}

.aggregate-grid .metric-item-full {
  justify-content: flex-start;
  gap: 20px;
}

.aggregate-grid .metric-item-full .metric-value {
  text-align: left;
}

.quote-grid span,
.trade-grid span,
.aggregate-grid span {
  font-size: 0.72rem;
  color: #5a8772;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.metric-value {
  color: #1f5139;
  font-size: 0.8rem;
  font-weight: 700;
  text-align: right;
  min-width: 0;
  max-width: none;
  white-space: normal;
  overflow-wrap: anywhere;
}

.stock-rating {
  margin-top: 8px;
  color: #4d735f;
  font-size: 0.74rem;
}

.stock-card-actions {
  margin-top: 6px;
  padding-top: 0;
  display: flex;
  gap: 8px;
  align-items: stretch;
  min-width: 0;
}

.stock-add-to-cart-btn,
.stock-add-to-watchlist-btn {
  flex: 1;
  min-width: 0;
  border: none;
  border-radius: 8px;
  padding: 9px 8px;
  font-weight: 700;
  font-size: 0.74rem;
  white-space: normal;
  overflow: visible;
  text-overflow: clip;
  line-height: 1.25;
  text-align: center;
  cursor: pointer;
  transition: transform 0.15s, box-shadow 0.15s;
}

.stock-add-to-cart-btn {
  background: linear-gradient(135deg, #15803d 0%, #22c55e 100%);
  color: #fff;
  box-shadow: 0 4px 12px rgba(34, 197, 94, 0.2);
}

.stock-add-to-cart-btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 6px 16px rgba(34, 197, 94, 0.28);
}

.stock-add-to-watchlist-btn {
  background: #fff3e0;
  color: #e67e22;
  border: 1px solid #ffe0b2;
}

.stock-add-to-watchlist-btn:hover {
  background: #ffe0b2;
  transform: translateY(-1px);
}

.error-message {
  color: #c0392b;
  font-weight: 600;
  padding: 16px;
  background: #fef2f2;
  border: 1px solid #fecaca;
  border-radius: 8px;
  margin-top: 12px;
}

.loading-message {
  color: #4d735f;
  font-weight: 500;
  padding: 16px;
  text-align: center;
  margin-top: 12px;
}

.no-data-message {
  color: #4d735f;
  font-weight: 500;
  padding: 16px;
  text-align: center;
  margin-top: 12px;
  background: #f3fff6;
  border-radius: 8px;
}



@media (prefers-reduced-motion: reduce) {
  .home-btn-primary,
  .home-btn-secondary,
  .stock-card {
    transition: none;
  }

  .home-btn-primary:hover,
  .home-btn-secondary:hover,
  .stock-card:hover {
    transform: none;
  }
}

